#include <batteries/random/zipf.hpp>

#include <benchmark/benchmark.h>

#include <batteries/async/runtime.hpp>

#include <batteries/int_types.hpp>

namespace {

using namespace batt::int_types;

void Benchmark_ZipfThreadScaling(benchmark::State& state)
{
    // Pre-benchmark setup.
    //
    batt::WorkerPool worker_pool{(usize)state.range(0), batt::Runtime::instance().default_scheduler()};

    // Benchmark.
    //
    for (auto _ : state) {
        batt::ZipfIntDistribution<i64> zipf{1.0, 0, 100 * 1000 * 1000, worker_pool};
    }

    // Post-benchmark cleanup.
}

BENCHMARK(Benchmark_ZipfThreadScaling)  //
    ->RangeMultiplier(2)                //
    ->Range(1, std::thread::hardware_concurrency());

}  //namespace
